  "objectives": [
    "להבדיל בין דפוסי השימוש של Cell ו‑RefCell",
    "להשתמש ב‑Cell למוטיביות פנימית פשוטה",
    "להשוות התנהגות של טיפוסים Copy ולא‑Copy עם Cell"
